const msg = $input.first().json;
const binary = $input.first().binary || {};

const from = msg.from || '';
const fromMatch = from.match(/^(.+?)\s*<(.+?)>$/);
const fromName = fromMatch ? fromMatch[1].trim() : null;
const fromEmail = fromMatch ? fromMatch[2].trim() : from.trim();

const toRaw = Array.isArray(msg.to) ? msg.to : [msg.to || ''];
const toAddresses = toRaw.map(t => { const m = t.match(/<(.+?)>/); return m ? m[1] : t.trim(); }).filter(Boolean);

// Haal bijlagemetadata op uit binary velden (geen data, alleen naam/type/grootte)
const attachments = Object.entries(binary)
  .filter(([key]) => key.startsWith('attachment'))
  .map(([, bin]) => ({
    name: bin.fileName || 'bijlage',
    mimeType: bin.mimeType || 'application/octet-stream',
    size: bin.fileSize || 0,
  }));

return [{
  json: {
    externalId: msg.id,
    fromName,
    fromEmail,
    toAddresses,
    ccAddresses: [],
    subject: msg.subject || '(geen onderwerp)',
    bodyText: msg.text || null,
    bodyHtml: msg.html || null,
    threadId: msg.threadId || null,
    receivedAt: msg.date || new Date().toISOString(),
    attachments: attachments.length > 0 ? attachments : undefined,
  }
}];
